parameters.functionCode:
const response = $input.first().json;
const analysis = JSON.parse(response.content[0].text);
const fileName = $('Extract Contract Text').first().json.fileName;

const riskEmoji = {'high': '🔴', 'medium': '🟡', 'low': '🟢'};
let report = `📄 CONTRACT RISK ANALYSIS\n\nContract: ${fileName}\nOverall Risk: ${riskEmoji[analysis.overall_risk]} ${analysis.overall_risk.toUpperCase()}\n\n${analysis.summary}\n\n`;

if (analysis.risks.length > 0) {
  report += `⚠️ RISKS (${analysis.risks.length}):\n\n`;
  analysis.risks.forEach((r, i) => {
    report += `${i+1}. ${riskEmoji[r.severity]} ${r.category}: ${r.issue}\n   Recommendation: ${r.recommendation}\n\n`;
  });
}

return [{json: {report, risks: analysis.risks, fileName}}];
